import{_ as a,o,c as i,ag as t}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"Cross-Project Sync Note: Standardized Wrapper Authorization Model","description":"","frontmatter":{},"headers":[],"relativePath":"sessions/2026-03-03-policy-wrapper-standardization/07_CROSS_PROJECT_SYNC_NOTE.md","filePath":"sessions/2026-03-03-policy-wrapper-standardization/07_CROSS_PROJECT_SYNC_NOTE.md"}'),r={name:"sessions/2026-03-03-policy-wrapper-standardization/07_CROSS_PROJECT_SYNC_NOTE.md"};function l(n,e,s,d,c,p){return o(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="cross-project-sync-note-standardized-wrapper-authorization-model" tabindex="-1">Cross-Project Sync Note: Standardized Wrapper Authorization Model <a class="header-anchor" href="#cross-project-sync-note-standardized-wrapper-authorization-model" aria-label="Permalink to &quot;Cross-Project Sync Note: Standardized Wrapper Authorization Model&quot;">​</a></h1><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>Disseminate the policy-wrapper split architecture so Cursor/Claude/Codex/Droid/host surfaces can share the same conditional gate behavior while preserving existing static command contracts.</p><h2 id="standardized-model-to-sync" tabindex="-1">Standardized model to sync <a class="header-anchor" href="#standardized-model-to-sync" aria-label="Permalink to &quot;Standardized model to sync&quot;">​</a></h2><ul><li>Static host-side rules remain authoritative for unconditional command allow/deny/request and are exported per platform as today.</li><li>Conditional logic remains centralized in <code>policy-wrapper-*</code> binaries through <code>policy-wrapper-rules.json</code>.</li><li>Host hooks call <code>wrappers/policy-wrapper-dispatch.sh</code> for commands that survive the static surface.</li><li>Fallback behavior is explicit via manifest fields: <ul><li><code>fallback_missing_policy</code></li><li><code>fallback_malformed_bundle</code></li><li><code>fallback_condition_eval_error</code></li></ul></li></ul><h2 id="candidate-targets-for-adoption" tabindex="-1">Candidate targets for adoption <a class="header-anchor" href="#candidate-targets-for-adoption" aria-label="Permalink to &quot;Candidate targets for adoption&quot;">​</a></h2><ol><li><code>thegent</code><ul><li>Existing multi-platform wrapper consumers and host adapter integration points.</li></ul></li><li><code>cliproxyapi++</code><ul><li>Already maintaining command-policy surfaces with similar hook constraints.</li></ul></li><li><code>portage</code><ul><li>Runtime-heavy CLI host interactions; deterministic fallback and hard-fail modes reduce silent-policy regressions.</li></ul></li><li><code>heliosCLI</code><ul><li>Developer-tool surfaces with frequent local execution paths benefit from standardized host hook behavior.</li></ul></li><li><code>tokenledger</code> and <code>trash-cli</code><ul><li>Follows quickly if policy surfaces are already host-export based.</li></ul></li></ol><h2 id="rollout-sequence" tabindex="-1">Rollout sequence <a class="header-anchor" href="#rollout-sequence" aria-label="Permalink to &quot;Rollout sequence&quot;">​</a></h2><ol><li>Share <code>wrappers/README.md</code> command contract and fallback semantics.</li><li>Share <code>policy-wrapper-dispatch.sh</code> behavior and manifest keys in the target repo issue/template.</li><li>Run dispatch smoke test spec before any host rule changes: <ul><li>one positive command decision</li><li>one blocked command decision</li></ul></li><li>Enable include-conditional host exports in sync tooling after parity checks.</li><li>Add child-agent follow-up WBS lane in each repo for host-adapter closure.</li></ol><h2 id="governance-note" tabindex="-1">Governance note <a class="header-anchor" href="#governance-note" aria-label="Permalink to &quot;Governance note&quot;">​</a></h2><p>Use the same cross-repo coordination pattern used in this session:</p><ul><li>one standardized child-agent delegation model for discovery + execution</li><li>lane-level WBS status ledger with explicit acceptance gates</li><li>manifest-backed fallback rationale for every host integration decision.</li></ul>',12)])])}const m=a(r,[["render",l]]);export{u as __pageData,m as default};
